# ── 生成JSON ──
FIELDS = ["name", "nature", "taste", "meridian", "effect", "indications", "contra", "usage", "nutrition", "desc"]
veggies = [dict(zip(FIELDS, row)) for row in VEGGIES_RAW]

# 去重
seen = set()
unique = []
for v in veggies:
    key = v["name"]
    if key not in seen:
        seen.add(key)
        unique.append(v)

# 写入JSON
out_path = os.path.join(os.path.dirname(os.path.abspath(__file__)), "veggies_data.json")
with open(out_path, "w", encoding="utf-8") as f:
    json.dump(unique, f, ensure_ascii=False, indent=2)

print(f"✅ 共生成 {len(unique)} 种蔬菜食材（去重后）")
print(f"📄 保存到: {out_path}")

# 统计寒热属性
nature_count = {}
for v in unique:
    n = v["nature"]
    nature_count[n] = nature_count.get(n, 0) + 1
print(f"\n📊 寒热属性分布:")
for n in ["寒", "凉", "平", "温", "热"]:
    if n in nature_count:
        print(f"  {n}性: {nature_count[n]}种")
